#include <stdio.h>
#include <stdlib.h>
#define MAX 1000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T, N, K, i, j, sum, comparisons;
    int files[MAX];
    scanf("%d", &T);
    for (i = 0; i < T; i++) {
        scanf("%d %d", &N, &K);
        for (j = 0; j < N; j++) {
            scanf("%d", &files[j]);
        }
        qsort(files, N, sizeof(int), compare);
        comparisons = 0;
        while (N > 1) {
            sum = 0;
            for (j = 0; j < K && j < N; j++) {
                sum += files[j];
            }
            comparisons += sum;
            for (j = K; j < N; j++) {
                files[j - K] = files[j];
            }
            N -= K - 1;
            qsort(files, N, sizeof(int), compare);
        }
        printf("Case %d: %d\n", i + 1, comparisons);
    }
    return 0;
}

