int main() {
    int T, N, K, i, j, sum, comparisons;
    cin >> T;
    for (i = 0; i < T; i++) {
        cin >> N >> K;
        priority_queue<int, vector<int>, greater<int>> pq;
        for (j = 0; j < N; j++) {
            int x;
            cin >> x;
            pq.push(x);
        }
        comparisons = 0;
        while (pq.size() > 1) {
            sum = 0;
            for (j = 0; j < K && j < pq.size(); j++) {
                sum += pq.top();
                pq.pop();
            }
            comparisons += sum;
            pq.push(sum);
        }
        cout << "Case " << i + 1 << ": " << comparisons << endl;
    }
    return 0;
}

