import java.util.PriorityQueue;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int i = 0; i < T; i++) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            PriorityQueue<Integer> pq = new PriorityQueue<>();
            for (int j = 0; j < N; j++) {
                int x = sc.nextInt();
                pq.add(x);
            }
            long comparisons = 0;
            while (pq.size() > 1) {
                long sum = 0;
                for (int j = 0; j < K && j < pq.size(); j++) {
                    sum += pq.poll();
                }
                comparisons += sum;
                pq.add((int) sum);
            }
            System.out.println("Case " + (i + 1) + ": " + comparisons);
        }
    }
}

