const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function readline() {
    return lines[idx++];
}

let T = parseInt(readline());
for (let i = 0; i < T; i++) {
    let [N, K] = readline().split(' ').map(x => parseInt(x));
    let files = readline().split(' ').map(x => parseInt(x));
    let pq = [];
    for (let file of files) {
        pq.push(file);
    }
    pq.sort((a, b) => a - b);
    let comparisons = 0;
    while (pq.length > 1) {
        let sum = 0;
        for (let j = 0; j < Math.min(K, pq.length); j++) {
            sum += pq.shift();
        }
        comparisons += sum;
        pq.push(sum);
        pq.sort((a, b) => a - b);
    }
    console.log(`Case ${i + 1}: ${comparisons}`);
}
